document.addEventListener("DOMContentLoaded",(()=>{if("undefined"==typeof gsap)return;gsap.registerPlugin(ScrollTrigger);const e=document.querySelector(".trip-activities-grid-widget");if(!e)return;const r=e.querySelectorAll(".trip-activities-grid-card");r.length&&gsap.from(r,{scrollTrigger:{trigger:e,start:"top 80%"},opacity:0,y:40,scale:.9,duration:.8,ease:"power3.out",stagger:.15,clearProps:"all"})}));